import React, { Fragment, useState, useEffect } from 'react';
import { Card, CardHeader, CardBody, Row, Col, Form, Dropdown, DropdownToggle, DropdownMenu, DropdownItem } from 'reactstrap';
import DataTable from 'react-data-table-component';
import { H3, Breadcrumbs, Btn } from '../../AbstractElements';
import { useNavigate } from 'react-router-dom';
import { getClientUrlDataToken } from '../../Utils/restUtils';
import { Add, ExpenseSummaryRep, ExpenseSummaryList, incomeSummaryRep, incomeSummaryList, Filter, Search, Export } from '../../Constant';
import SearchList from '../../CommonElements/Search';
import { getcategoryincome, getcategoryincomeRole, incomeSummary, incomeSummaryRole, selectHeaders, selectHeadersRole, viewPackageReport, viewPackageReportRole } from '../../CommonUrl';
import { useSelector } from 'react-redux';
import { ExpenseSummaryColumns, incomeSummaryColumns } from './Header/ReportTableHeader';
import { useForm } from 'react-hook-form';
import { getYearOption, typeOption, yearOptions } from './DropDownOption';
import HandleApiError from '../Common/ErrorImport/ErrorImport';

const IncomeSummary = () => {
    const { register, handleSubmit, control, formState: { errors } } = useForm({});
    const authState = useSelector((state) => state.auth);
    const searchParams = location.search;
    const params = new URLSearchParams(searchParams);

    const [customerLists, setCustomerList] = useState([]);
    const [searchKeyword, setSearchKeyword] = useState('');
    const [resetPaginationToggle, setResetPaginationToggle] = useState(false);
    const [loading, setLoading] = useState(false);
    const [totalRows, setTotalRows] = useState(0);
    const [perPage, setPerPage] = useState(10);
    const [headerOPtion, setapiHeader] = useState([]);
    const [categoryOption, setCategory] = useState([]);
    const [dropdownOpen, setDropdownOpen] = useState(false);
    const [currentPage, setCurrentPage] = useState(1);
    const [filters, setFilters] = useState({
        year: params.get('year') || new Date().getFullYear(),
        headerId: params.get('headerId') || '',
        type: params.get('type') || '',
        category: params.get('category') || '',
        search: params?.get('search') || ''
    })
    const navigate = useNavigate();

    const toggleDropdown = () => setDropdownOpen(!dropdownOpen);
    const toggleStyle = { padding: '10px 20px', opacity: '0.8', fontSize: '14px' }


    const fetchIncomeSummary = async (page, size = perPage) => {
        setLoading(true);
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? incomeSummary + `?page=${page}&page_length=${size}&search=${filters.search}&type=${filters?.type}&search=${filters?.search}&year=${filters?.year}&${filters?.type === 'sales' ? `category_id=${filters.category}` : `header_id=${filters.headerId}`}` : incomeSummaryRole +
            `?page=${page}&page_length=${size}&search=${filters.search}&type=${filters?.type}&search=${filters?.search}&year=${filters?.year}&${filters?.type === 'sales' ? `category_id=${filters.category}` : `header_id=${filters.headerId}`}`);
        if (response.status === true) {
            setResetPaginationToggle(!resetPaginationToggle);
            setLoading(true);
            setCustomerList(response?.data?.map((item, index) => {
                return {
                    Si: index + 1,
                    type: item?.type,
                    Category: item?.name,
                    January: item?.Jan,
                    February: item?.Feb,
                    March: item?.Mar,
                    April: item.Apr,
                    May: item.May,
                    June: item.Jun,
                    July: item.Jul,
                    August: item.Aug,
                    September: item.Sep,
                    October: item.Oct,
                    November: item.Nov,
                    December: item.Dec
                }
            }
            ))
            setLoading(false);
            setTotalRows(response.data.total);
            setLoading(false);

        } else if (response.status >= 400 && response.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (response.status >= 500 && response.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
        setLoading(false);
    };

    useEffect(() => {
        fetchIncomeSummary(1);
        headerData()
        categoryData()
    }, []);

    const handlePageChange = page => {
        fetchIncomeSummary(page);
        setCurrentPage(page);
    };


    const headerData = async () => {
        const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? selectHeaders : selectHeadersRole);
        if (data.status === true) {
            setapiHeader(data.data);
        } else {
            HandleApiError(navigate, data.status);
        }
    };

    const categoryData = async () => {
        const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getcategoryincome : getcategoryincomeRole);
        if (data.status === true) {
            const option = data?.data?.map((item) => (
                {
                    label: item?.name,
                    value: item?.id,
                }
            ))
            setCategory(option);
        } else {
            HandleApiError(data.status);
        }
    };


    const handlePerRowsChange = async (newPerPage, page) => {
        fetchIncomeSummary(page, newPerPage);
        setPerPage(newPerPage);
    };

    const handleOnchangeType = (e) => {
        setFilters({ ...filters, type: e.target.value, category: '', headerId: '' })

    }

    const onSubmit = (data) => {
        const year = filters?.year || '';
        const headerId = filters?.headerId || '';
        const category = filters?.type === '' ? '' : filters?.category || '';
        const type = filters?.type || '';
        const search = filters?.search || '';

        setFilters({
            year,
            headerId,
            category,
            type,
            search
        });


        const queryParams = new URLSearchParams({
            year: year,
            headerId: headerId,
            category: category,
            type: type,
            search: search
        }).toString();

        navigate(`/report/income-summary?${queryParams}`);
    }

      const exportDueExcel = async () => {
            setLoading(true);
            const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getCollectionDue +
                `?export=collection_due_data&search=${filters?.searchKey ? filters.searchKey : ''}&start_date=${formatStartDate ?? ''}&end_date=${formatEndDate ?? ''}&area_id=${filters?.areaFilter ?? ''}&status=${filters?.statusFilter ?? ''}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}` :
                getCollectionDueRole + `?export=collection_due_data&search=${filters?.searchKey ? filters.searchKey : ''}&start_date=${formatStartDate ?? ''}&end_date=${formatEndDate ?? ''}&area_id=${filters?.areaFilter ?? ''}&status=${filters?.statusFilter ?? ''}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`);
            const dataToExport = response.data.map(({ subscriber_id, customer_status, customer_name, customer_address, area_name, order_balance, invoice_count }) => ({ Subscriber_id: subscriber_id, Status: customer_status, Name: customer_name, Route_No: customer_address, Area: area_name, Balance: order_balance, Number_of_Invoice: invoice_count }));
            if (response.status === true) {
                const ws = XLSX.utils.json_to_sheet(dataToExport);
                const wb = XLSX.utils.book_new();
                XLSX.utils.book_append_sheet(wb, ws, 'Collection Due Data');
                XLSX.writeFile(wb, 'collection_due_data.xlsx');
            } else {
                handleApiError(data.status);
            }
            setLoading(false);
        };
    
        const exportDuePdf = async () => {
            setLoading(true);
            const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getCollectionDue +
                `?export=collection_due_data&search=${filters?.searchKey ? filters.searchKey : ''}&start_date=${formatStartDate ?? ''}&end_date=${formatEndDate ?? ''}&area_id=${filters?.areaFilter ?? ''}&status=${filters?.statusFilter ?? ''}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}` :
                getCollectionDueRole + `?export=collection_due_data&search=${filters?.searchKey ? filters.searchKey : ''}&start_date=${formatStartDate ?? ''}&end_date=${formatEndDate ?? ''}&area_id=${filters?.areaFilter ?? ''}&status=${filters?.statusFilter ?? ''}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`);
            const dataToExport = response.data.map(({ subscriber_id, customer_status, customer_name, customer_address, area_name, order_balance, invoice_count }, index) => ({ Sl: index + 1, subscriber_id, customer_status, customer_name, customer_address, area_name, order_balance, invoice_count }));
            if (response.status === true) {
                const doc = new jsPDF();
                const columns = ["Sl", "Subscriber id", "Status", "Name", "Route No", "Area", "Balance", "Number of Invoice"];
                const rows = dataToExport.map(({ subscriber_id, customer_status, customer_name, customer_address, area_name, order_balance, invoice_count }, index) => [index + 1, subscriber_id, customer_status, customer_name, customer_address, area_name, order_balance, invoice_count]);
                doc.autoTable({
                    head: [columns],
                    body: rows,
                    columnStyles: {
                        0: { cellWidth: 11 },
                        4: { cellWidth: 30 },
                    },
                    styles: { fontSize: 10 },
                    headStyles: { fillColor: [100, 150, 200] },
                });
                doc.save("collection_due_data.pdf");
            } else {
                handleApiError(data.status);
            }
            setLoading(false);
        };

        

    return (
        <Fragment>
            <Breadcrumbs mainTitle={incomeSummaryRep} parent="Reports" title={incomeSummaryRep} />
            <Card>
                <CardHeader style={{  display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <H3>{incomeSummaryList}</H3>
                    </div>
                    <Dropdown isOpen={dropdownOpen} toggle={toggleDropdown}>
                        <DropdownToggle color="#fff" style={{ fontSize: '14px', zIndex: 1000 }} className="btn btn-primary mr-4">
                            {Export} <i className="icofont icofont-arrow-up"></i>
                        </DropdownToggle>
                        <DropdownMenu container="body">
                            <DropdownItem style={toggleStyle}  ><i className="fa fa-file-excel-o me-2"></i> Excel</DropdownItem>
                            <DropdownItem style={toggleStyle} ><i className="fa fa-file-pdf-o me-2"></i> Pdf</DropdownItem>
                        </DropdownMenu>
                    </Dropdown>
                </CardHeader>
                <Form className="needs-validation" noValidate onSubmit={handleSubmit(onSubmit)}>
                    <Row className='ps-3 gap-sm-3 gap-md-2 filterGap'>
                        <Col sm="12" md="2" className="form-element">
                            <input value={filters?.search} onChange={(e) => { setFilters({ ...filters, search: e.target.value }) }} className="form-control" placeholder={Search} type="text"
                            />
                        </Col>
                        <Col sm="12" md="2" className="form-element">
                            <select className="form-select" value={filters?.year} onChange={(e) => { setFilters({ ...filters, year: e.target.value }) }}  >
                                {/* <option key='year'>Year</option> */}
                                {getYearOption().map((values, index) => (
                                    <option key={values} value={values}>{values}</option>
                                ))}
                            </select>
                        </Col>
                        <Col sm="12" md="2" className="form-element">
                            <select className="form-select" value={filters?.type} onChange={(e) => { handleOnchangeType(e) }}  >
                                <option value='' key='type'>Type</option>
                                {typeOption.map((values, index) => (
                                    <option key={values.value} value={values.value}>{values.label}</option>
                                ))}
                            </select>
                        </Col>
                        {
                            filters?.type == 'income' ?
                                <Col sm="12" md="2" className="form-element">
                                    <select className="form-select" value={filters?.headerId} onChange={(e) => { setFilters({ ...filters, headerId: e.target.value }) }}  >
                                        <option value=''>Header</option>

                                        {
                                            headerOPtion?.map((item) => (
                                                <option value={item?.id}  >{item?.title}</option>
                                            ))
                                        }

                                    </select>
                                </Col> : filters?.type == 'sales' &&
                                <Col sm="12" md="2" className="form-element">
                                    <select className="form-select" value={filters?.category} onChange={(e) => { setFilters({ ...filters, category: e.target.value }) }}  >
                                        <option value=''>Category</option>

                                        {
                                            categoryOption?.map((item) => (
                                                <option value={item?.value}  >{item?.label}</option>
                                            ))
                                        }

                                    </select>
                                </Col>

                        }

                        <Col sm="12" md="2" className="custom-filtrs">
                            <Btn attrBtn={{ color: "primary" }} type="submit">{Filter}</Btn>
                        </Col>
                    </Row>
                </Form>

                <CardBody>
                    <div className="order-history table-responsive">
                        <DataTable
                            columns={incomeSummaryColumns}
                            data={customerLists}
                            progressPending={loading}
                            pagination
                            paginationServer
                            defaultSortAsc
                            paginationRowsPerPageOptions={[10, 25, 50, 100]}
                            paginationTotalRows={totalRows}
                            paginationDefaultPage={currentPage}
                            onChangeRowsPerPage={handlePerRowsChange}
                            onChangePage={handlePageChange}
                            fixedHeader
                        />
                    </div>
                </CardBody>
            </Card>
        </Fragment>
    );
};

export default IncomeSummary;